// n8n Code Node - Extract Contact Data from Apollo Bulk Enrichment Response

const items = $input.all();
const extractedContacts = [];

for (const item of items) {
  const data = item.json;

  // Check if matches array exists
  const matches = data.matches || [];

  matches.forEach(person => {
    extractedContacts.push({
      json: {
        // Basic identification
        id: person.id || '',
        first_name: person.first_name || '',
        last_name: person.last_name || '',
        name: person.name || '',

        // Contact information
        email: person.email || '',
        email_status: person.email_status || '',
        phone: person.organization?.phone || person.organization?.primary_phone?.number || '',
        linkedin_url: person.linkedin_url || '',

        // Professional information
        title: person.title || '',
        position: person.title || '', // Same as title
        headline: person.headline || '',
        seniority: person.seniority || '',

        // Company/Organization information
        company_name: person.organization?.name || '',
        organization_id: person.organization_id || '',
        organization_website: person.organization?.website_url || '',
        organization_phone: person.organization?.phone || '',
        organization_domain: person.organization?.primary_domain || '',
        organization_industry: person.organization?.industry || '',
        organization_employees: person.organization?.estimated_num_employees || '',
        organization_revenue: person.organization?.organization_revenue_printed || '',

        // Location information
        city: person.city || '',
        state: person.state || '',
        country: person.country || '',
        formatted_address: person.formatted_address || '',

        // Additional useful fields
        photo_url: person.photo_url || '',
        personal_emails: (person.personal_emails || []).join('; '),
        departments: (person.departments || []).join('; '),
        subdepartments: (person.subdepartments || []).join('; '),
        functions: (person.functions || []).join('; '),

        // Current employment
        current_company: person.employment_history?.[0]?.organization_name || '',
        current_title: person.employment_history?.[0]?.title || '',
        current_start_date: person.employment_history?.[0]?.start_date || '',
      }
    });
  });
}

return extractedContacts;

// Prepare data for Reoon Bulk Verification
const items = $input.all();

// Collect all emails into an array
const emails = items
  .map(item => item.json.email)
  .filter(email => email && email !== '' && email !== '<REDACTED_EMAIL>');

// Return single item with the array
return [{
  json: {
    name: `k ${new Date().toISOString()}`,
    emails: emails,  // This is an array
    key: "<REOON_API_KEY>"  // Replace with your actual API key
  }
}];

// Pass only verified (valid / catch_all / safe) emails
// n8n Code Node

// Allowed email statuses
const allowedStatuses = ['valid', 'catch_all', 'verified', 'safe'];
const allowedOuterStatuses = ['running', 'completed'];

// 1. Extract people items (with emails and email_status)
const prospectItems = items.filter(
  item => item.json && typeof item.json.email === 'string' && item.json.email_status
);

// 2. Extract verification results items (from Reoon API response)
// Check outer status is 'running' or 'completed'
const verifyItems = items.filter(
  item =>
    item.json &&
    typeof item.json.results === 'object' &&
    allowedOuterStatuses.includes(item.json.status)
);

// 3. Create a Set of emails marked as valid, catch_all, verified, or safe
const allowedEmails = new Set();

// Add emails from Reoon verification results
// Check inner status within results object
verifyItems.forEach(item => {
  const results = item.json.results || {};
  Object.entries(results).forEach(([email, result]) => {
    if (
      result &&
      result.status &&
      allowedStatuses.includes(result.status)
    ) {
      allowedEmails.add(email.toLowerCase().trim());
    }
  });
});

// 4. Filter people to include only those with allowed emails
// Check BOTH: email in allowedEmails Set OR email_status in allowedStatuses
const filteredOutput = prospectItems
  .filter(item => {
    const email = item.json.email.toLowerCase().trim();
    const emailStatus = item.json.email_status;

    // Pass if email is in verified set OR if email_status is allowed
    return allowedEmails.has(email) || allowedStatuses.includes(emailStatus);
  })
  .map(item => ({ json: item.json }));

// 5. Return filtered leads
return filteredOutput;

// n8n Code node — limit to <= 3 leads per organization_domain, keep full records, dedupe

const MAX_PER_DOMAIN = 3;

const items = $input.all();

// Normalize a domain-ish string (strip protocol, trailing paths, leading www)
function normalizeDomain(raw) {
  const s = String(raw || '').toLowerCase().trim();
  if (!s) return '';
  // strip protocol
  let d = s.replace(/^https?:\/\//, '');
  // take until first slash
  d = d.split('/')[0];
  // strip leading www.
  d = d.replace(/^www\./, '');
  return d;
}

// Stable dedupe key for a person/lead
function dedupeKey(j) {
  if (j.id) return `id:${String(j.id)}`;
  const email = String(j.email || '').toLowerCase().trim();
  const li = String(j.linkedin_url || '').toLowerCase().trim();
  const name = String(j.name || '').toLowerCase().trim();
  const orgId = String(j.organization_id || '').toLowerCase().trim();
  const title = String(j.current_title || j.title || '').toLowerCase().trim();
  const orgDomain = normalizeDomain(j.organization_domain);
  return `k:${email}|${li}|${name}|${orgId}|${title}|${orgDomain}`;
}

const seenPerDomain = new Map(); // domain -> Set(keys)
const keptCount = new Map();     // domain -> number kept
const out = [];

for (const item of items) {
  const j = item.json || {};
  const domain = normalizeDomain(j.organization_domain);

  // skip if no domain (change to include if you prefer: just remove this continue)
  if (!domain) continue;

  // init maps
  if (!seenPerDomain.has(domain)) seenPerDomain.set(domain, new Set());
  if (!keptCount.has(domain)) keptCount.set(domain, 0);

  // enforce max per domain
  if (keptCount.get(domain) >= MAX_PER_DOMAIN) continue;

  // dedupe within domain
  const key = dedupeKey(j);
  const seenSet = seenPerDomain.get(domain);
  if (seenSet.has(key)) continue;

  seenSet.add(key);
  keptCount.set(domain, keptCount.get(domain) + 1);

  // keep full original record
  out.push({ json: j });
}

return out;

