// 1. Get all the incoming items (the list of people).
const items = $input.all();

// 2. Use .map() to transform each person object into the required format.
const formattedDetails = items.map(item => {
  const person = item.json;

  // Create a new, smaller object with only the fields Apollo needs for matching.
  // We include several fields to improve the match accuracy.
  return {
    first_name: person.first_name,
    last_name: person.last_name,
    linkedin_url: person.linkedin_url,
    organization_domain: person.organization_domain,
    title: person.title,
    id: person.id
  };
});

// 3. Create the final request body object, which has a single key "details".
const requestBody = {
  details: formattedDetails
};

// 4. Return the result as a single item.
// The next node (HTTP Request) will use this output as its body.
return [{
  json: {
    // We name the output 'body' for easy reference in the HTTP Request node.
    body: requestBody
  }
}];

