// n8n Code Node — Filter by:
// 1) isMatchingDomain? === "True"
// 2) Industry contains "accounting" or "bookkeeping" (case-insensitive)
// 3) Company Size is "Unknown" OR within 1–200 employees
// Returns original structure (item.json as-is)

const itemsIn = $input.all();

function parseSize(sizeStrRaw) {
  const sizeStr = String(sizeStrRaw || "").trim();
  if (!sizeStr || sizeStr.toLowerCase() === "unknown") {
    return { lower: null, upper: null, unknown: true };
  }

  // Match numeric range e.g. "11-50 employees", "701–1000 employees", "501-1,000"
  const rangeMatch = sizeStr.match(/(\d[\d,]*)\s*[-–]\s*(\d[\d,]*)/);
  if (rangeMatch) {
    const lower = parseInt(rangeMatch[1].replace(/,/g, ""), 10);
    const upper = parseInt(rangeMatch[2].replace(/,/g, ""), 10);
    return { lower, upper, unknown: false };
  }

  // Match open-ended e.g. "10,001+ employees"
  const plusMatch = sizeStr.match(/(\d[\d,]*)\s*\+/);
  if (plusMatch) {
    const lower = parseInt(plusMatch[1].replace(/,/g, ""), 10);
    return { lower, upper: null, unknown: false };
  }

  // If cannot parse, treat as unknown to avoid over-filtering
  return { lower: null, upper: null, unknown: true };
}

const filtered = itemsIn.filter(item => {
  const out = item?.json?.output;
  if (!out || typeof out !== "object") return false;

  const isMatch = String(out["isMatchingDomain?"] || "").toLowerCase() === "true";
  if (!isMatch) return false;

  const industryStr = String(out["Industry"] || "").toLowerCase();
  const isAccountingIndustry =
    industryStr.includes("accounting") || industryStr.includes("bookkeeping");
  if (!isAccountingIndustry) return false;

  const { lower, upper, unknown } = parseSize(out["Company Size"]);

  // Allow Unknown size
  if (unknown) return true;

  // Otherwise require 1–200 employees
  const lowerOk = (lower !== null ? lower <= 200 : true);
  const upperOk = (upper === null || upper <= 200);
  return lowerOk && upperOk;
});

// Return original structure unchanged for items that pass
return filtered.map(item => ({ json: item.json }));

