}

function normList(v) {
  // industries might be a comma-separated string or an array
  if (Array.isArray(v)) return v.map(normStr);
  const s = normStr(v);
  return s ? s.split(',').map(x => x.trim()) : [];
}

const allowed = itemsIn.filter(item => {
