// n8n Code node (JavaScript)
// Filters to only accounting/bookkeeping roles (no Account Managers)
// Input: either a single item whose .json is an array of job objects,
//        or multiple items where each .json is a job object.
// Output: items with json: {
//   key, url, title, joburl, employerName, employerCompanyPage, employeeCount, city, country, companyIndeedUrl
// }

const rawInputs = $input.all().map(it => it.json || it);

// ---- helpers ----
const get = (obj, path, fallback = null) => {
  if (!obj) return fallback;
  const parts = path.split('.');
  let cur = obj;
  for (const p of parts) {
    if (cur && (p in cur)) cur = cur[p];
    else return fallback;
  }
  return cur;
};

const normStr = v => String(v || '').toLowerCase().trim();

const normList = v => {
  if (Array.isArray(v)) return v.map(x => normStr(x));
  const s = normStr(v);
  return s ? s.split(',').map(x => x.trim()) : [];
};

function extractCountry(url) {
  if (!url) return null;
  try {
    const domain = new URL(url).hostname;
    if (domain.includes('.co.in')) return 'India';
    if (domain.includes('.co.uk')) return 'United Kingdom';
    if (domain.includes('.ca')) return 'Canada';
    if (domain.includes('.com.au')) return 'Australia';
    if (domain.includes('.com')) return 'United States';
    return 'Unknown';
  } catch (e) {
    return null;
  }
}

function extractCity(job) {
  // prefer structured location if available
  const locCity = get(job, 'location.city') || get(job, 'location.cityName');
  if (locCity) return String(locCity).trim();

  const title = get(job, 'title') || get(job, 'jobTitle') || '';
  // common patterns: "for Portland based", "in Portland", "... - Portland, OR"
  let m = title.match(/\b(?:in|for|at)\s([A-Z][a-zA-Z]+(?:[\s-][A-Z][a-zA-Z]+)?)\b/);
  if (m) return m[1];

  // try joburl pattern like "...-portland-based-..."
  const joburl = get(job, 'jobUrl') || get(job, 'joburl') || get(job, 'url');
  if (joburl) {
    m = joburl.match(/-([a-z]+)-based/i);
    if (m) return m[1].charAt(0).toUpperCase() + m[1].slice(1);
    const cityMatch = joburl.match(/\/jobs?\/.*-([a-z-]+)-\d+/i);
    if (cityMatch) {
      const parts = cityMatch[1].split('-');
      return parts.map(p => p.charAt(0).toUpperCase() + p.slice(1)).join(' ');
    }
  }
  return null;
}

// ---- flatten inputs ----
let jobs = [];
for (const r of rawInputs) {
  if (!r) continue;
  if (Array.isArray(r)) {
    jobs.push(...r);
  } else if (typeof r === 'object') {
    // if object contains the array as a property (e.g., { data: [...] })
    const firstArray = Object.values(r).find(v => Array.isArray(v));
    if (firstArray && firstArray.every(i => i && typeof i === 'object' && ('key' in i || 'title' in i))) {
      jobs.push(...firstArray);
    } else {
      jobs.push(r);
    }
  } else {
    // ignore non-objects
  }
}

// ---- filtering ----
function isAccountingJob(job) {
  const j = job || {};
  const title = normStr(get(j, 'title') || get(j, 'jobTitle') || get(j, 'position') || '');
  const jobFunction = normStr(get(j, 'jobFunction') || '');
  const industries = normList(get(j, 'industries') || get(j, 'industry') || '');

  // exclude account manager / account management (sales)
  if (/\baccount\s+manager\b/.test(title) || /\baccount\s+management\b/.test(title)) {
    return false;
  }

  // title-based checks
  const isAccountantTitle  = /\baccountant(s)?\b/.test(title);    // accountant, accountants
  const isBookkeeperTitle  = /\bbookkeeper(s)?\b/.test(title);    // bookkeeper, bookkeepers

  // function / industry checks
  const isAccountingFunction = jobFunction.includes('accounting') || jobFunction.includes('auditing');
  const isAccountingIndustry = industries.some(i => i.includes('accounting') || i.includes('bookkeeping') || i.includes('auditing'));

  return isAccountantTitle || isBookkeeperTitle || isAccountingFunction || isAccountingIndustry;
}

// apply filter
const filtered = jobs.filter(isAccountingJob);

// ---- map to desired output ----
const out = filtered.map(job => {
  const key = get(job, 'key', null);
  const url = get(job, 'url', null);
  const joburl = get(job, 'jobUrl', get(job, 'joburl', null));
