  const employeeCount = get(job, 'employer.employeesCount', '') || null;

  const employerCompanyPage = employerName
    ? `${employerName} (${companyUrl || ''})`
    : (companyUrl || null);

  const companyIndeedUrl = companyUrl || null;
  const city = extractCity(job);
  const country = extractCountry(url);
  const website = get(job,'employer.corporateWebsite','')||null;
  return {
    json: {
      key,
      url,
      title,
      joburl,
      employerName,
      employerCompanyPage,
      employeeCount,
      city,
      country,
      companyIndeedUrl,
      website
    }
  };
});

return out;

return items.map(j => ({
